#include <algorithm>
#include <cstddef>
#include <cstdlib>
#include <fstream>
#include <iostream>
#include <sstream>
#include <stdexcept>
#include <string>
#include <vector>

#include "cJSON.h"
#include "lodepng.h"

struct Layer {
    std::vector<double> weight;
    std::vector<double> bias;
    std::size_t in_dim = 0;
    std::size_t out_dim = 0;
};

struct Model {
    Layer input_layer;
    Layer hidden_layer;
    Layer output_layer;
};

std::string read_file(const char* path) {
    std::ifstream in(path, std::ios::binary);
    if (!in) {
        throw std::runtime_error(std::string("failed to open ") + path);
    }
    std::ostringstream ss;
    ss << in.rdbuf();
    return ss.str();
}

cJSON* require_object_item(cJSON* object, const char* key) {
    cJSON* item = cJSON_GetObjectItemCaseSensitive(object, key);
    if (!cJSON_IsObject(item)) {
        throw std::runtime_error(std::string("missing object: ") + key);
    }
    return item;
}

int require_int(cJSON* object, const char* key) {
    cJSON* item = cJSON_GetObjectItemCaseSensitive(object, key);
    if (!cJSON_IsNumber(item)) {
        throw std::runtime_error(std::string("missing number: ") + key);
    }
    return item->valueint;
}

std::vector<double> require_number_array(cJSON* object, const char* key, std::size_t expected_size) {
    cJSON* array = cJSON_GetObjectItemCaseSensitive(object, key);
    if (!cJSON_IsArray(array)) {
        throw std::runtime_error(std::string("missing array: ") + key);
    }
    if (static_cast<std::size_t>(cJSON_GetArraySize(array)) != expected_size) {
        throw std::runtime_error(std::string("unexpected array size: ") + key);
    }

    std::vector<double> values;
    values.reserve(expected_size);
    cJSON* value = nullptr;
    cJSON_ArrayForEach(value, array) {
        if (!cJSON_IsNumber(value)) {
            throw std::runtime_error(std::string("non-numeric array entry: ") + key);
        }
        values.push_back(value->valuedouble);
    }
    return values;
}

Layer load_layer(cJSON* root, const char* name, std::size_t out_dim, std::size_t in_dim) {
    cJSON* layer_object = require_object_item(root, name);
    Layer layer;
    layer.in_dim = in_dim;
    layer.out_dim = out_dim;
    layer.weight = require_number_array(layer_object, "weight", out_dim * in_dim);
    layer.bias = require_number_array(layer_object, "bias", out_dim);
    return layer;
}

Model load_model(const char* weights_path) {
    std::string json = read_file(weights_path);
    cJSON* root = cJSON_ParseWithLength(json.data(), json.size());
    if (!root) {
        throw std::runtime_error("failed to parse weights JSON");
    }

    try {
        const int input_dim = require_int(root, "input_dim");
        const int hidden_dim = require_int(root, "hidden_dim");
        const int num_classes = require_int(root, "num_classes");
        if (input_dim <= 0 || hidden_dim <= 0 || num_classes <= 0) {
            throw std::runtime_error("model dimensions must be positive");
        }

        Model model;
        model.input_layer = load_layer(root, "input_layer", hidden_dim, input_dim);
        model.hidden_layer = load_layer(root, "hidden_layer", hidden_dim, hidden_dim);
        model.output_layer = load_layer(root, "output_layer", num_classes, hidden_dim);
        cJSON_Delete(root);
        return model;
    } catch (...) {
        cJSON_Delete(root);
        throw;
    }
}

std::vector<double> linear_relu(const std::vector<double>& x, const Layer& layer) {
    std::vector<double> y(layer.out_dim);
    for (std::size_t out = 0; out < layer.out_dim; ++out) {
        double sum = layer.bias[out];
        const std::size_t offset = out * layer.in_dim;
        for (std::size_t in = 0; in < layer.in_dim; ++in) {
            sum += layer.weight[offset + in] * x[in];
        }
        y[out] = std::max(0.0, sum);
    }
    return y;
}

std::vector<double> linear(const std::vector<double>& x, const Layer& layer) {
    std::vector<double> y(layer.out_dim);
    for (std::size_t out = 0; out < layer.out_dim; ++out) {
        double sum = layer.bias[out];
        const std::size_t offset = out * layer.in_dim;
        for (std::size_t in = 0; in < layer.in_dim; ++in) {
            sum += layer.weight[offset + in] * x[in];
        }
        y[out] = sum;
    }
    return y;
}

std::vector<double> load_image_vector(const char* image_path, std::size_t expected_pixels) {
    std::vector<unsigned char> rgba;
    unsigned width = 0;
    unsigned height = 0;
    const unsigned error = lodepng::decode(rgba, width, height, std::string(image_path), LCT_RGBA, 8);
    if (error) {
        throw std::runtime_error(std::string("failed to decode PNG: ") + lodepng_error_text(error));
    }
    if (static_cast<std::size_t>(width) * static_cast<std::size_t>(height) != expected_pixels) {
        throw std::runtime_error("image pixel count does not match model input size");
    }

    std::vector<double> pixels(expected_pixels);
    for (std::size_t i = 0; i < expected_pixels; ++i) {
        const double r = rgba[4 * i + 0];
        const double g = rgba[4 * i + 1];
        const double b = rgba[4 * i + 2];
        const double a = rgba[4 * i + 3] / 255.0;
        const double luminance = (0.2126 * r + 0.7152 * g + 0.0722 * b) * a;
        pixels[i] = luminance / 255.0;
    }
    return pixels;
}

int predict(const Model& model, const std::vector<double>& input) {
    std::vector<double> h1 = linear_relu(input, model.input_layer);
    std::vector<double> h2 = linear_relu(h1, model.hidden_layer);
    std::vector<double> logits = linear(h2, model.output_layer);
    return static_cast<int>(std::max_element(logits.begin(), logits.end()) - logits.begin());
}

int main(int argc, char** argv) {
    if (argc != 3) {
        std::cerr << "usage: " << argv[0] << " weights.json image.png\n";
        return 1;
    }

    try {
        Model model = load_model(argv[1]);
        std::vector<double> input = load_image_vector(argv[2], model.input_layer.in_dim);
        std::cout << predict(model, input);
        return 0;
    } catch (const std::exception& e) {
        std::cerr << "error: " << e.what() << '\n';
        return 1;
    }
}
